create table dirkspzm32.isi_log (
    log_time       timestamp(6) not null enable,
    log_category   varchar2(50 char) not null enable,
    log_error_code number(*, 5),
    log_details    varchar2(2550 char) not null enable,
    log_typ        varchar2(5 char) not null enable,
    log_level      number(*, 5) default 4,
    log_status     varchar2(10 char),
    log_programm   varchar2(100 char),
    log_modul      varchar2(100 char),
    log_computer   varchar2(30 char),
    log_msg_count  number(*, 0),
    sid            varchar2(2 char),
    firma_nr       number(6, 0),
    log_id         number(*, 0)
);

alter table dirkspzm32.isi_log
    add constraint pk_isi_log primary key ( log_time,
                                            log_details )
        using index enable;


